solution_code:
#include <iostream>

int square(int x) {
    return x * x;
}

int sumOfSquares(int a, int b) {
    return square(a) + square(b);
}

int main() {
    int a {}, b {};
    std::cin >> a >> b;
    std::cout << sumOfSquares(a, b) << '\n';
    return 0;
}
